import { cn } from '@utils/cn';
import { getColor } from '@utils/helper';
import { Component, mergeProps, Show } from 'solid-js';
import type { IndicatorProps } from './indicator.types';
import type { BaseColorProps } from '@/type';

const DEFAULT_PROPS = {
  count: 0,
  showExact: false,
  color: 'error' as BaseColorProps,
  top: 0,
  right: 0,
};

function formatCount(count: number, showExact: boolean): string {
  if (count > 99 && !showExact) return '99+';
  return String(count);
}

function isPill(text: string): boolean {
  return text.length > 2;
}

function toPx(value: number | string): string {
  return typeof value === 'number' ? `${value}px` : value;
}

export const Indicator: Component<IndicatorProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);

  const label = () => formatCount(p.count, p.showExact);
  const pill = () => isPill(label());

  return (
    <div class={cn('in01', p.class?.root)}>
      {p.children}
      <Show when={p.count > 0}>
        <span
          class={cn('in02', pill() ? 'in04' : 'in03', getColor(p.color), p.class?.badge)}
          style={{
            '--in-top': toPx(p.top),
            '--in-right': toPx(p.right),
          }}
        >
          {label()}
        </span>
      </Show>
    </div>
  );
};
